  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });
  // verify token...
  next();
};

app.get('/users', authenticate, (req, res) => { ... });
```

---

### 9. 🟡 No Request Logging
There's no audit trail for requests, making security incident investigation difficult.

**Fix:** Add structured logging with `morgan` or `pino-http`:
```js
const morgan = require('morgan');
app.use(morgan('combined')); // Logs IP, method, path, status, response time
```

---

