    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    res.json(users);
  } catch (err) {
    next(err); // Forward to error handler
  }
});

// --- 404 Handler (must be after all routes) ---
app.use((req, res) => {
  res.status(404).json({ error: 'Route not found.' });
});

